def get_square_roots(a, p, q):
    # 1. Square root mod p
    # Assumes p % 4 == 3 for simplicity (common in CTFs)
    r_p = pow(a, (p + 1) // 4, p)
    # 2. Square root mod q
    r_q = pow(a, (q + 1) // 4, q)
    
    # 3. Combine with CRT
    # We need to solve for x where x = r_p mod p and x = r_q mod q
    # Using the standard CRT formula
    inv_p = pow(p, -1, q)
    inv_q = pow(q, -1, p)
    
    roots = []
    for s_p in [r_p, p - r_p]:
        for s_q in [r_q, q - r_q]:
            x = (s_p * q * inv_q + s_q * p * inv_p) % (p * q)
            roots.append(x)
    return roots

# Initial ciphertext is our starting point
current_level_roots = [ct]

# We need to take the square root 16 times (2^16 = 65536)
for i in range(16):
    next_level_roots = []
    for root in current_level_roots:
        try:
            possible_roots = get_square_roots(root, p, q)
            # FILTER: If we were at the final step, we'd look for "flag{"
            # But during intermediate steps, we just keep all valid mathematical roots
            next_level_roots.extend(possible_roots)
        except:
            continue 
    
    current_level_roots = next_level_roots
    # OPTIONAL: If the list gets too big, filter for printable ASCII
    # current_level_roots = [r for r in current_level_roots if is_mostly_ascii(r)]

# Final check
for final_m in current_level_roots:
    msg = long_to_bytes(final_m)
    if b"flag" in msg:
        print(f"Found: {msg}")